from typing import Annotated, TypedDict
import operator

# --- Replace semantics (default) ---
class ReplaceState(TypedDict):
    query: str       # last write wins
    answer: str      # last write wins
    attempts: int    # last write wins

# If node_a returns {"attempts": 2} and node_b returns {"attempts": 3},
# the final value is 3 (second writer wins — avoid this for parallel nodes).

# --- Additive reducer ---
class AddState(TypedDict):
    messages: Annotated[list, operator.add]
    # node_a: {"messages": [msg1]}
    # node_b: {"messages": [msg2]}
    # result: {"messages": [msg1, msg2]}   ← both appended

# --- Custom reducer ---
def keep_max(a: int, b: int) -> int:
    return max(a, b)

class CustomState(TypedDict):
    score: Annotated[int, keep_max]
    # node_a: {"score": 5}
    # node_b: {"score": 8}
    # result: {"score": 8}   ← keep_max applied

