import pytest
from langgraph.checkpoint.memory import MemorySaver
from langgraph.graph import StateGraph, START, END
from typing import Annotated
from typing_extensions import TypedDict
import operator

class CountState(TypedDict):
    count: int
    log: Annotated[list[str], operator.add]

def increment(state: CountState) -> dict:
    return {"count": state["count"] + 1, "log": [f"incremented to {state['count'] + 1}"]}

def double(state: CountState) -> dict:
    return {"count": state["count"] * 2, "log": [f"doubled to {state['count'] * 2}"]}

@pytest.fixture
def app():
    g = StateGraph(CountState)
    g.add_node("inc", increment)
    g.add_node("dbl", double)
    g.add_edge(START, "inc")
    g.add_edge("inc", "dbl")
    g.add_edge("dbl", END)
    return g.compile(checkpointer=MemorySaver())

def test_state_after_each_step(app):
    config = {"configurable": {"thread_id": "test-1"}}
    # Run the full graph
    result = app.invoke({"count": 3, "log": []}, config=config)

    # Final state
    assert result["count"] == 8   # (3 + 1) * 2
    assert result["log"] == ["incremented to 4", "doubled to 8"]

    # Inspect state history — newest first
    history = list(app.get_state_history(config))
    assert len(history) == 3  # after dbl, after inc, initial

def test_external_state_update(app):
    config = {"configurable": {"thread_id": "test-2"}}
    app.invoke({"count": 5, "log": []}, config=config)

    # Inject an external correction
    app.update_state(config, {"count": 99, "log": ["corrected externally"]})
    patched = app.get_state(config)
    assert patched.values["count"] == 99
    assert "corrected externally" in patched.values["log"]
